import { useLocation } from "react-router-dom";
import { useState, useEffect } from "react";
import "./styles/Books.css";

function LibrarianBooks() {
  const location = useLocation();
  const genre = location.state?.genre || "Literature";

  const [books, setBooks] = useState([]);

  // TEMP data (frontend only)
  useEffect(() => {
    const demoBooks = [
      {
        title: "Sample Book 1",
        author: "Author One",
        cover: "https://via.placeholder.com/200x280",
        status: "Available",
      },
      {
        title: "Sample Book 2",
        author: "Author Two",
        cover: "https://via.placeholder.com/200x280",
        status: "Issued",
      },
    ];
    setBooks(demoBooks);
  }, [genre]);

  return (
    <div className="books-page">
      <h1 className="books-title">
        Manage {genre} Books
      </h1>

      <div className="books-grid">
        {books.map((book, i) => (
          <div key={i} className="book-card">
            <img src={book.cover} alt={book.title} />
            <h3>{book.title}</h3>
            <p>{book.author}</p>

            <p className={`status ${book.status === "Available" ? "avail" : "not-avail"}`}>
              {book.status}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default LibrarianBooks;
